   172вҶ’}
   173вҶ’
   174вҶ’export interface AnimationState {
   175вҶ’  isAnimating: boolean;
   176вҶ’  startTime: number;
   177вҶ’  duration: number;
   178вҶ’  startX: number;
   179вҶ’  startY: number;
