   196вҶ’
   197вҶ’// Initial state
   198вҶ’const initialState: ViewportSliceState = {
   199вҶ’  camera: { x: 0, y: 0, zoom: 1 },
   200вҶ’  canvasSize: { width: 0, height: 0 },
   201вҶ’  isInitialized: false,
