   598вҶ’## 2.4 LOD System
   599вҶ’
   600вҶ’### 2.4.1 Three-Layer Architecture
   601вҶ’
   602вҶ’| Layer | Zoom Range | Visualization | Max Instances | Purpose |
   603вҶ’|-------|------------|---------------|---------------|---------|
   604вҶ’| **MACRO** | < 0.5x | Heatmap cells | 600 | 10-20 year strategic view |
   605вҶ’| **MESO** | 0.5x - 2.0x | Task blocks | 100,000 (pre-alloc) | 2-5 year tactical view |
   606вҶ’| **MICRO** | > 2.0x | HTML labels + curves | 50 labels | 4-8 week operational view |
   607вҶ’
   608вҶ’### 2.4.2 LOD Thresholds and Blend Zones
   609вҶ’
   610вҶ’```typescript
   611вҶ’// File: apps/canvas/src/canvas/InfiniteCanvas.tsx
   612вҶ’
   613вҶ’// LOD switching thresholds
   614вҶ’const LOD_THRESHOLDS = {
   615вҶ’  macroToMeso: 0.5,   // Below 0.5 = MACRO, above = MESO
   616вҶ’  mesoToMicro: 2.0,   // Above 2.0 = MICRO
   617вҶ’};
   618вҶ’
   619вҶ’// Blend zone size (zoom units on each side of threshold)
   620вҶ’const BLEND_ZONE_SIZE = 0.15;
   621вҶ’
   622вҶ’// Transition duration (milliseconds)
   623вҶ’const LOD_TRANSITION_DURATION = 100;
   624вҶ’
   625вҶ’/**
   626вҶ’ * Calculate layer opacities for smooth crossfade transitions.
   627вҶ’ * Both layers render during blend zones with interpolated opacity.
   628вҶ’ */
   629вҶ’function calculateLayerOpacities(zoom: number): {
   630вҶ’  macro: number;
   631вҶ’  meso: number;
   632вҶ’  micro: number;
   633вҶ’} {
   634вҶ’  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
   635вҶ’
   636вҶ’  // Blend zone boundaries
   637вҶ’  const macroEnd = macroToMeso - BLEND_ZONE_SIZE;   // 0.35
   638вҶ’  const mesoStart = macroToMeso + BLEND_ZONE_SIZE;  // 0.65
   639вҶ’  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE;    // 1.85
   640вҶ’  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
   641вҶ’
   642вҶ’  let macro = 0;
   643вҶ’  let meso = 0;
   644вҶ’  let micro = 0;
   645вҶ’
   646вҶ’  // MACRO opacity: 1 below macroEnd, fade to 0 through blend zone
   647вҶ’  if (zoom <= macroEnd) {
   648вҶ’    macro = 1;
   649вҶ’  } else if (zoom < mesoStart) {
   650вҶ’    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   651вҶ’    macro = 1 - t;
   652вҶ’  }
   653вҶ’
   654вҶ’  // MESO opacity: fade in from macroEnd, full from mesoStart to mesoEnd, fade out
   655вҶ’  if (zoom < macroEnd) {
   656вҶ’    meso = 0;
   657вҶ’  } else if (zoom < mesoStart) {
   658вҶ’    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   659вҶ’    meso = t;
   660вҶ’  } else if (zoom <= mesoEnd) {
   661вҶ’    meso = 1;
   662вҶ’  } else if (zoom < microStart) {
   663вҶ’    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   664вҶ’    meso = 1 - t;
   665вҶ’  }
   666вҶ’
   667вҶ’  // MICRO opacity: 0 until mesoEnd, fade in through blend zone, 1 above microStart
   668вҶ’  if (zoom <= mesoEnd) {
   669вҶ’    micro = 0;
   670вҶ’  } else if (zoom < microStart) {
   671вҶ’    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   672вҶ’    micro = t;
   673вҶ’  } else {
   674вҶ’    micro = 1;
   675вҶ’  }
   676вҶ’
   677вҶ’  return { macro, meso, micro };
   678вҶ’}
   679вҶ’```
   680вҶ’
   681вҶ’### 2.4.3 LODLayers Component
   682вҶ’
   683вҶ’```typescript
   684вҶ’// File: apps/canvas/src/canvas/InfiniteCanvas.tsx
   685вҶ’
   686вҶ’function LODLayers({ tasks, trainCount }: { tasks: TaskRender[]; trainCount: number }) {
   687вҶ’  const zoom = useCanvasSelector(s => s.viewport.camera.zoom);
   688вҶ’
   689вҶ’  const opacities = useMemo(
   690вҶ’    () => calculateLayerOpacities(zoom),
   691вҶ’    [zoom]
   692вҶ’  );
   693вҶ’
   694вҶ’  // Only render layers that have opacity > 0
   695вҶ’  return (
   696вҶ’    <group>
   697вҶ’      {opacities.macro > 0 && (
   698вҶ’        <MacroLayer
   699вҶ’          tasks={tasks}
   700вҶ’          trainCount={trainCount}
   701вҶ’          opacity={opacities.macro}
   702вҶ’        />
   703вҶ’      )}
   704вҶ’
   705вҶ’      {opacities.meso > 0 && (
   706вҶ’        <MesoLayer
   707вҶ’          tasks={tasks}
   708вҶ’          opacity={opacities.meso}
   709вҶ’        />
   710вҶ’      )}
   711вҶ’
   712вҶ’      {opacities.micro > 0 && (
   713вҶ’        <MicroLayer
   714вҶ’          tasks={tasks}
   715вҶ’          opacity={opacities.micro}
   716вҶ’        />
   717вҶ’      )}
   718вҶ’    </group>
   719вҶ’  );
   720вҶ’}
   721вҶ’```
   722вҶ’
   723вҶ’### 2.4.4 Crossfade Implementation Details
   724вҶ’
   725вҶ’**Material Configuration for Transparency:**
   726вҶ’
   727вҶ’```typescript
   728вҶ’// During LOD transitions, materials must be transparent
   729вҶ’<meshBasicMaterial
   730вҶ’  toneMapped={false}           // Accurate colors
   731вҶ’  transparent={opacity < 1}    // Enable transparency only when blending
   732вҶ’  opacity={opacity}
   733вҶ’  depthWrite={opacity >= 0.5}  // Prevent z-fighting: fading layer doesn't write depth
   734вҶ’/>
   735вҶ’```
   736вҶ’
   737вҶ’**Why depthWrite matters:**
   738вҶ’
   739вҶ’During crossfade (both layers rendering):
   740вҶ’- `depthWrite: true` on both = z-fighting (visual artifacts)
   741вҶ’- `depthWrite: false` on fading layer = correct blending
   742вҶ’- Threshold at 0.5 ensures dominant layer controls depth
   743вҶ’
   744вҶ’### 2.4.5 MacroLayer Implementation
   745вҶ’
   746вҶ’```typescript
   747вҶ’// File: apps/canvas/src/canvas/layers/MacroLayer.tsx
   748вҶ’import { useMemo, useRef, useEffect } from 'react';
   749вҶ’import { InstancedMesh, Object3D, Color } from 'three';
   750вҶ’import { interpolateYlOrRd } from 'd3-scale-chromatic';
   751вҶ’
   752вҶ’interface MacroLayerProps {
   753вҶ’  tasks: TaskRender[];
   754вҶ’  trainCount: number;
   755вҶ’  totalYears?: number;
   756вҶ’  opacity?: number;
   757вҶ’}
   758вҶ’
   759вҶ’// Grid configuration (monthly cells)
   760вҶ’const MONTHS_PER_YEAR = 12;
   761вҶ’const CELL_WIDTH = 30 * 10;    // ~30 days * pxPerDay
   762вҶ’const CELL_HEIGHT = 24;         // = pxPerTrain
   763вҶ’const CELL_GAP = 2;
   764вҶ’
   765вҶ’export function MacroLayer({
   766вҶ’  tasks,
   767вҶ’  trainCount,
   768вҶ’  totalYears = 10,
   769вҶ’  opacity = 1
   770вҶ’}: MacroLayerProps) {
   771вҶ’  const meshRef = useRef<InstancedMesh>(null);
   772вҶ’
   773вҶ’  // Reusable objects (GC prevention)
   774вҶ’  const tempObject = useMemo(() => new Object3D(), []);
   775вҶ’  const tempColor = useMemo(() => new Color(), []);
   776вҶ’
   777вҶ’  const totalMonths = totalYears * MONTHS_PER_YEAR;
   778вҶ’  const totalCells = trainCount * totalMonths;
   779вҶ’
   780вҶ’  // Calculate density grid (memoized)
   781вҶ’  const densityGrid = useMemo(
   782вҶ’    () => calculateDensityGrid(tasks, trainCount, totalMonths),
   783вҶ’    [tasks, trainCount, totalMonths]
   784вҶ’  );
   785вҶ’
   786вҶ’  // Update instance matrices and colors
   787вҶ’  useEffect(() => {
   788вҶ’    if (!meshRef.current) return;
   789вҶ’    const mesh = meshRef.current;
   790вҶ’
   791вҶ’    let instanceIndex = 0;
   792вҶ’    for (let trainIndex = 0; trainIndex < trainCount; trainIndex++) {
   793вҶ’      for (let monthIndex = 0; monthIndex < totalMonths; monthIndex++) {
   794вҶ’        // Position
   795вҶ’        const x = monthIndex * CELL_WIDTH + CELL_WIDTH / 2;
   796вҶ’        const y = -trainIndex * CELL_HEIGHT - CELL_HEIGHT / 2;
   797вҶ’
   798вҶ’        tempObject.position.set(x, y, 0);
   799вҶ’        tempObject.scale.set(CELL_WIDTH - CELL_GAP, CELL_HEIGHT - CELL_GAP, 1);
   800вҶ’        tempObject.updateMatrix();
   801вҶ’        mesh.setMatrixAt(instanceIndex, tempObject.matrix);
   802вҶ’
   803вҶ’        // Color based on density
   804вҶ’        const density = densityGrid[trainIndex]?.[monthIndex] ?? 0;
   805вҶ’        const colorHex = getHeatmapColor(density);
   806вҶ’        tempColor.set(colorHex);
   807вҶ’        mesh.setColorAt(instanceIndex, tempColor);
   808вҶ’
   809вҶ’        instanceIndex++;
   810вҶ’      }
   811вҶ’    }
   812вҶ’
   813вҶ’    mesh.instanceMatrix.needsUpdate = true;
   814вҶ’    if (mesh.instanceColor) {
   815вҶ’      mesh.instanceColor.needsUpdate = true;
   816вҶ’    }
   817вҶ’  }, [densityGrid, trainCount, totalMonths, tempObject, tempColor]);
   818вҶ’
   819вҶ’  return (
   820вҶ’    <instancedMesh
   821вҶ’      ref={meshRef}
   822вҶ’      args={[undefined, undefined, totalCells]}
   823вҶ’    >
   824вҶ’      <planeGeometry args={[1, 1]} />
   825вҶ’      <meshBasicMaterial
   826вҶ’        toneMapped={false}
   827вҶ’        transparent={opacity < 1}
   828вҶ’        opacity={opacity}
   829вҶ’        depthWrite={opacity >= 0.5}
   830вҶ’        vertexColors
   831вҶ’      />
   832вҶ’    </instancedMesh>
   833вҶ’  );
   834вҶ’}
   835вҶ’
   836вҶ’function calculateDensityGrid(
   837вҶ’  tasks: TaskRender[],
   838вҶ’  trainCount: number,
   839вҶ’  totalMonths: number
   840вҶ’): number[][] {
   841вҶ’  const grid: number[][] = Array(trainCount)
   842вҶ’    .fill(null)
   843вҶ’    .map(() => Array(totalMonths).fill(0));
   844вҶ’
   845вҶ’  const DAYS_PER_MONTH = 30;
   846вҶ’
   847вҶ’  for (const task of tasks) {
   848вҶ’    const monthStart = Math.floor(task.startDay / DAYS_PER_MONTH);
   849вҶ’    const monthEnd = Math.floor((task.startDay + task.duration) / DAYS_PER_MONTH);
   850вҶ’
   851вҶ’    for (let m = monthStart; m <= monthEnd && m < totalMonths; m++) {
   852вҶ’      if (m >= 0 && task.trainIndex < trainCount) {
   853вҶ’        grid[task.trainIndex][m]++;
   854вҶ’      }
   855вҶ’    }
   856вҶ’  }
   857вҶ’
   858вҶ’  return grid;
   859вҶ’}
   860вҶ’
   861вҶ’function getHeatmapColor(density: number): string {
   862вҶ’  // Normalize density (0 = empty, 1 = max)
   863вҶ’  // d3-scale-chromatic: Yellow -> Orange -> Red
   864вҶ’  const normalized = Math.min(density / 5, 1);  // Cap at 5 tasks per cell
   865вҶ’  return density === 0 ? '#f8fafc' : interpolateYlOrRd(normalized);
   866вҶ’}
   867вҶ’```
