  1049вҶ’## 2.5 Performance Architecture
  1050вҶ’
  1051вҶ’### 2.5.1 Core Performance Requirements
  1052вҶ’
  1053вҶ’| Metric | Target | Validation Confidence |
  1054вҶ’|--------|--------|----------------------|
  1055вҶ’| **Frame Rate** | 60fps constant | 70% (desktop) |
  1056вҶ’| **Frame Budget** | < 16.67ms | 70% (desktop) |
  1057вҶ’| **Viewport Query** | < 1ms | 95% (RBush verified) |
  1058вҶ’| **LOD Transition** | < 100ms | 90% |
  1059вҶ’| **Initial Load** | < 3s | Not tested |
  1060вҶ’| **Memory** | < 100MB stable | 80% |
  1061вҶ’
  1062вҶ’### 2.5.2 InstancedMesh Pre-allocation (DECISION-007)
  1063вҶ’
  1064вҶ’**Problem:** Dynamic InstancedMesh count causes GPU buffer reallocation.
  1065вҶ’
  1066вҶ’```typescript
  1067вҶ’// WRONG: Recreates GPU buffer when tasks.length changes
  1068вҶ’<instancedMesh args={[geometry, material, tasks.length]}>
  1069вҶ’
  1070вҶ’// CORRECT: Pre-allocate to maximum, control visibility with mesh.count
  1071вҶ’const MAX_INSTANCES = 100000;
  1072вҶ’
  1073вҶ’<instancedMesh ref={meshRef} args={[geometry, material, MAX_INSTANCES]}>
  1074вҶ’  {/* ... */}
  1075вҶ’</instancedMesh>
  1076вҶ’
  1077вҶ’// In useEffect:
  1078вҶ’mesh.count = actualTaskCount;  // Only render this many
  1079вҶ’```
  1080вҶ’
  1081вҶ’**Memory Cost:**
  1082вҶ’- 100k instances x 64 bytes (matrix + color) = ~6.4MB GPU memory
  1083вҶ’- Negligible compared to frame drops during reallocation
  1084вҶ’
  1085вҶ’### 2.5.3 RBush Spatial Indexing (DECISION-008: MANDATORY)
  1086вҶ’
  1087вҶ’**All viewport queries MUST use RBush. Array.filter() is FORBIDDEN.**
  1088вҶ’
  1089вҶ’```typescript
  1090вҶ’// File: apps/canvas/src/spatial/RBushSpatialIndex.ts
  1091вҶ’import RBush from 'rbush';
  1092вҶ’
  1093вҶ’interface RBushItem {
  1094вҶ’  minX: number;
  1095вҶ’  minY: number;
  1096вҶ’  maxX: number;
  1097вҶ’  maxY: number;
  1098вҶ’  id: string;
  1099вҶ’}
  1100вҶ’
  1101вҶ’export class RBushSpatialIndex {
  1102вҶ’  private tree: RBush<RBushItem>;
  1103вҶ’  private itemsById: Map<string, RBushItem> = new Map();
  1104вҶ’
  1105вҶ’  constructor() {
  1106вҶ’    this.tree = new RBush();
  1107вҶ’  }
  1108вҶ’
  1109вҶ’  /**
  1110вҶ’   * Bulk load tasks into spatial index.
  1111вҶ’   * O(n log n) - 2-3x faster than sequential insert.
  1112вҶ’   * Post-bulk-load queries are 20-30% faster.
  1113вҶ’   */
  1114вҶ’  load(tasks: TaskRender[]): void {
  1115вҶ’    this.tree.clear();
  1116вҶ’    this.itemsById.clear();
  1117вҶ’
  1118вҶ’    const items: RBushItem[] = tasks.map(task => ({
  1119вҶ’      minX: task.startDay * PX_PER_DAY,
  1120вҶ’      maxX: (task.startDay + task.duration) * PX_PER_DAY,
  1121вҶ’      minY: -task.trainIndex * PX_PER_TRAIN - PX_PER_TRAIN,
  1122вҶ’      maxY: -task.trainIndex * PX_PER_TRAIN,
  1123вҶ’      id: task.id,
  1124вҶ’    }));
  1125вҶ’
  1126вҶ’    for (const item of items) {
  1127вҶ’      this.itemsById.set(item.id, item);
  1128вҶ’    }
  1129вҶ’
  1130вҶ’    this.tree.load(items);  // Bulk load
  1131вҶ’  }
  1132вҶ’
  1133вҶ’  /**
  1134вҶ’   * Query tasks visible in viewport.
  1135вҶ’   * O(log n + k) where k = result count.
  1136вҶ’   */
  1137вҶ’  queryViewport(bounds: ViewportBounds): string[] {
  1138вҶ’    const OVERSCAN = 100;  // Render slightly outside for smooth panning
  1139вҶ’
  1140вҶ’    const results = this.tree.search({
  1141вҶ’      minX: bounds.minX - OVERSCAN,
  1142вҶ’      maxX: bounds.maxX + OVERSCAN,
  1143вҶ’      minY: bounds.minY - OVERSCAN,
  1144вҶ’      maxY: bounds.maxY + OVERSCAN,
  1145вҶ’    });
  1146вҶ’
  1147вҶ’    return results.map(item => item.id);
  1148вҶ’  }
  1149вҶ’
  1150вҶ’  /**
  1151вҶ’   * Find nearest task to a point (for hover detection).
  1152вҶ’   * Expanding radius search pattern.
  1153вҶ’   */
  1154вҶ’  queryNearest(x: number, y: number, maxDistance = 50): { id: string; distance: number } | null {
  1155вҶ’    let radius = 20;
  1156вҶ’    let nearest: { id: string; distance: number } | null = null;
  1157вҶ’
  1158вҶ’    while (radius <= maxDistance) {
  1159вҶ’      const candidates = this.tree.search({
  1160вҶ’        minX: x - radius,
  1161вҶ’        maxX: x + radius,
  1162вҶ’        minY: y - radius,
  1163вҶ’        maxY: y + radius,
  1164вҶ’      });
  1165вҶ’
  1166вҶ’      for (const item of candidates) {
  1167вҶ’        const centerX = (item.minX + item.maxX) / 2;
  1168вҶ’        const centerY = (item.minY + item.maxY) / 2;
  1169вҶ’        const dist = Math.sqrt((x - centerX) ** 2 + (y - centerY) ** 2);
  1170вҶ’
  1171вҶ’        if (dist <= maxDistance && (!nearest || dist < nearest.distance)) {
  1172вҶ’          nearest = { id: item.id, distance: dist };
  1173вҶ’        }
  1174вҶ’      }
  1175вҶ’
  1176вҶ’      if (nearest) return nearest;
  1177вҶ’      radius *= 2;
  1178вҶ’    }
  1179вҶ’
  1180вҶ’    return nearest;
  1181вҶ’  }
  1182вҶ’}
  1183вҶ’```
  1184вҶ’
  1185вҶ’### 2.5.4 Object Pooling (DECISION-009: MANDATORY)
  1186вҶ’
  1187вҶ’**GC is the primary bottleneck in WebGL applications, not rendering.**
  1188вҶ’
  1189вҶ’Evidence:
  1190вҶ’- Single GC event can drop 11 frames (validated)
  1191вҶ’- GC timing is unpredictable
  1192вҶ’- Mobile devices especially sensitive
  1193вҶ’
  1194вҶ’**Pooling Pattern:**
  1195вҶ’
  1196вҶ’```typescript
  1197вҶ’// In component scope (created once, reused every frame)
  1198вҶ’const tempObject = useMemo(() => new Object3D(), []);
  1199вҶ’const tempColor = useMemo(() => new Color(), []);
  1200вҶ’const tempVector = useMemo(() => new Vector3(), []);
  1201вҶ’const tempMatrix = useMemo(() => new Matrix4(), []);
  1202вҶ’
  1203вҶ’// In animation loop
  1204вҶ’useFrame(() => {
  1205вҶ’  // CORRECT: Reuse pooled objects
  1206вҶ’  tempVector.set(x, y, z);
  1207вҶ’  ref.current.position.copy(tempVector);
  1208вҶ’
  1209вҶ’  // WRONG: Creates new object every frame (60 allocations/second)
  1210вҶ’  ref.current.position.copy(new Vector3(x, y, z));
  1211вҶ’});
  1212вҶ’```
  1213вҶ’
  1214вҶ’**For large-scale pooling:**
  1215вҶ’
  1216вҶ’```typescript
  1217вҶ’class ObjectPool<T> {
  1218вҶ’  private pool: T[] = [];
  1219вҶ’  private factory: () => T;
  1220вҶ’
  1221вҶ’  constructor(factory: () => T, initialSize: number = 50) {
  1222вҶ’    this.factory = factory;
  1223вҶ’    for (let i = 0; i < initialSize; i++) {
  1224вҶ’      this.pool.push(factory());
  1225вҶ’    }
  1226вҶ’  }
  1227вҶ’
  1228вҶ’  acquire(): T {
  1229вҶ’    return this.pool.pop() || this.factory();
  1230вҶ’  }
  1231вҶ’
  1232вҶ’  release(obj: T): void {
  1233вҶ’    this.pool.push(obj);
  1234вҶ’  }
  1235вҶ’}
  1236вҶ’
  1237вҶ’// Usage
  1238вҶ’const matrixPool = new ObjectPool(() => new Matrix4(), 100);
  1239вҶ’
  1240вҶ’function updateInstances() {
  1241вҶ’  const matrix = matrixPool.acquire();
  1242вҶ’  // ... use matrix ...
  1243вҶ’  matrixPool.release(matrix);
  1244вҶ’}
  1245вҶ’```
  1246вҶ’
  1247вҶ’### 2.5.5 GC Avoidance Strategies
  1248вҶ’
  1249вҶ’| Strategy | Implementation | Impact |
  1250вҶ’|----------|----------------|--------|
  1251вҶ’| **Object Pooling** | useMemo for temp objects | High |
  1252вҶ’| **metadata: false** | State machine config | Medium |
  1253вҶ’| **TypedArrays** | EntityStore SoA pattern | High |
  1254вҶ’| **Avoid closures** | store.getState() in RAF | Medium |
  1255вҶ’| **Pre-allocation** | InstancedMesh MAX_INSTANCES | High |
  1256вҶ’| **Bulk operations** | RBush.load() | Medium |
  1257вҶ’
  1258вҶ’### 2.5.6 60fps Target Constraints
  1259вҶ’
  1260вҶ’**Frame Budget: 16.67ms**
  1261вҶ’
  1262вҶ’| Operation | Budget | Priority |
  1263вҶ’|-----------|--------|----------|
  1264вҶ’| GPU Render | ~8ms | Critical |
  1265вҶ’| JavaScript | ~5ms | Critical |
  1266вҶ’| Layout/Paint | ~2ms | Low |
  1267вҶ’| GC | **0ms target** | **Eliminate** |
  1268вҶ’
  1269вҶ’**Rules:**
  1270вҶ’1. NO allocations in `useFrame` or `requestAnimationFrame`
  1271вҶ’2. NO React state updates in animation loops
  1272вҶ’3. Use `canvasStore.getState()` for synchronous reads
  1273вҶ’4. Profile with r3f-perf and PerfMonitor
  1274вҶ’
