### 2.4.2 LOD Thresholds and Blend Zones

```typescript
// File: apps/canvas/src/canvas/InfiniteCanvas.tsx

// LOD switching thresholds
const LOD_THRESHOLDS = {
  macroToMeso: 0.5,   // Below 0.5 = MACRO, above = MESO
  mesoToMicro: 2.0,   // Above 2.0 = MICRO
};

// Blend zone size (zoom units on each side of threshold)
const BLEND_ZONE_SIZE = 0.15;

// Transition duration (milliseconds)
const LOD_TRANSITION_DURATION = 100;

/**
 * Calculate layer opacities for smooth crossfade transitions.
 * Both layers render during blend zones with interpolated opacity.
 */
function calculateLayerOpacities(zoom: number): {
  macro: number;
  meso: number;
  micro: number;
} {
  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;

  // Blend zone boundaries
  const macroEnd = macroToMeso - BLEND_ZONE_SIZE;   // 0.35
  const mesoStart = macroToMeso + BLEND_ZONE_SIZE;  // 0.65
  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE;    // 1.85
  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15

  let macro = 0;
  let meso = 0;
  let micro = 0;

  // MACRO opacity: 1 below macroEnd, fade to 0 through blend zone
  if (zoom <= macroEnd) {
    macro = 1;
  } else if (zoom < mesoStart) {
    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    macro = 1 - t;
  }

  // MESO opacity: fade in from macroEnd, full from mesoStart to mesoEnd, fade out
  if (zoom < macroEnd) {
    meso = 0;
  } else if (zoom < mesoStart) {
    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    meso = t;
  } else if (zoom <= mesoEnd) {
    meso = 1;
  } else if (zoom < microStart) {
    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    meso = 1 - t;
  }

  // MICRO opacity: 0 until mesoEnd, fade in through blend zone, 1 above microStart
  if (zoom <= mesoEnd) {
    micro = 0;
  } else if (zoom < microStart) {
    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    micro = t;
  } else {
    micro = 1;
  }

  return { macro, meso, micro };
}
```

