### 2.4.4 Crossfade Implementation Details

**Material Configuration for Transparency:**

```typescript
// During LOD transitions, materials must be transparent
<meshBasicMaterial
  toneMapped={false}           // Accurate colors
  transparent={opacity < 1}    // Enable transparency only when blending
  opacity={opacity}
  depthWrite={opacity >= 0.5}  // Prevent z-fighting: fading layer doesn't write depth
/>
```

**Why depthWrite matters:**

During crossfade (both layers rendering):
- `depthWrite: true` on both = z-fighting (visual artifacts)
- `depthWrite: false` on fading layer = correct blending
- Threshold at 0.5 ensures dominant layer controls depth

### 2.4.5 MacroLayer Implementation

```typescript
// File: apps/canvas/src/canvas/layers/MacroLayer.tsx
import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';
import { interpolateYlOrRd } from 'd3-scale-chromatic';

interface MacroLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  totalYears?: number;
  opacity?: number;
}

// Grid configuration (monthly cells)
const MONTHS_PER_YEAR = 12;
const CELL_WIDTH = 30 * 10;    // ~30 days * pxPerDay
const CELL_HEIGHT = 24;         // = pxPerTrain
const CELL_GAP = 2;

export function MacroLayer({
  tasks,
  trainCount,
  totalYears = 10,
  opacity = 1
}: MacroLayerProps) {
  const meshRef = useRef<InstancedMesh>(null);

  // Reusable objects (GC prevention)
  const tempObject = useMemo(() => new Object3D(), []);
  const tempColor = useMemo(() => new Color(), []);

  const totalMonths = totalYears * MONTHS_PER_YEAR;
  const totalCells = trainCount * totalMonths;

  // Calculate density grid (memoized)
  const densityGrid = useMemo(
    () => calculateDensityGrid(tasks, trainCount, totalMonths),
    [tasks, trainCount, totalMonths]
  );

  // Update instance matrices and colors
  useEffect(() => {
    if (!meshRef.current) return;
    const mesh = meshRef.current;

    let instanceIndex = 0;
    for (let trainIndex = 0; trainIndex < trainCount; trainIndex++) {
      for (let monthIndex = 0; monthIndex < totalMonths; monthIndex++) {
        // Position
        const x = monthIndex * CELL_WIDTH + CELL_WIDTH / 2;
        const y = -trainIndex * CELL_HEIGHT - CELL_HEIGHT / 2;

        tempObject.position.set(x, y, 0);
        tempObject.scale.set(CELL_WIDTH - CELL_GAP, CELL_HEIGHT - CELL_GAP, 1);
        tempObject.updateMatrix();
        mesh.setMatrixAt(instanceIndex, tempObject.matrix);

        // Color based on density
        const density = densityGrid[trainIndex]?.[monthIndex] ?? 0;
        const colorHex = getHeatmapColor(density);
        tempColor.set(colorHex);
        mesh.setColorAt(instanceIndex, tempColor);

        instanceIndex++;
      }
    }

    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [densityGrid, trainCount, totalMonths, tempObject, tempColor]);

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, totalCells]}
    >
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial
        toneMapped={false}
        transparent={opacity < 1}
        opacity={opacity}
        depthWrite={opacity >= 0.5}
        vertexColors
      />
    </instancedMesh>
  );
}

function calculateDensityGrid(
  tasks: TaskRender[],
  trainCount: number,
  totalMonths: number
): number[][] {
  const grid: number[][] = Array(trainCount)
    .fill(null)
    .map(() => Array(totalMonths).fill(0));

  const DAYS_PER_MONTH = 30;

  for (const task of tasks) {
    const monthStart = Math.floor(task.startDay / DAYS_PER_MONTH);
    const monthEnd = Math.floor((task.startDay + task.duration) / DAYS_PER_MONTH);

    for (let m = monthStart; m <= monthEnd && m < totalMonths; m++) {
      if (m >= 0 && task.trainIndex < trainCount) {
        grid[task.trainIndex][m]++;
      }
    }
  }

  return grid;
}

function getHeatmapColor(density: number): string {
  // Normalize density (0 = empty, 1 = max)
  // d3-scale-chromatic: Yellow -> Orange -> Red
  const normalized = Math.min(density / 5, 1);  // Cap at 5 tasks per cell
  return density === 0 ? '#f8fafc' : interpolateYlOrRd(normalized);
}
```

### 2.4.6 MesoLayer Implementation

```typescript
// File: apps/canvas/src/canvas/layers/MesoLayer.tsx
import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color } from 'three';

// Pre-allocation constant (DECISION-007)
const MAX_INSTANCES = 100000;

// Visual constants
const TASK_HEIGHT = 18;
const HOVER_BRIGHTNESS = 0.3;

// Colors
const COLORS = {
  blue: '#3b82f6',    // maintenance
  orange: '#f59e0b',  // overhaul
  gray: '#9ca3af',    // inspection
};
const CONFLICT_COLOR = '#ef4444';
const SELECTION_COLOR = '#06b6d4';
const FOCUS_COLOR = '#8b5cf6';

interface MesoLayerProps {
  tasks: TaskRender[];
  opacity?: number;
}

export function MesoLayer({ tasks, opacity = 1 }: MesoLayerProps) {
  const meshRef = useRef<InstancedMesh>(null);

  // State for interactions
  const hoveredTaskId = useCanvasSelector(s => s.interaction.hoveredTaskId);
  const selectedTaskId = useCanvasSelector(s => s.interaction.selectedTaskId);
  const focusedTaskId = useCanvasSelector(s => s.interaction.focusedTaskId);

  // Reusable objects (MANDATORY: GC prevention)
  const tempObject = useMemo(() => new Object3D(), []);
  const tempColor = useMemo(() => new Color(), []);

  // Update instances when tasks or interactions change
  useEffect(() => {
    if (!meshRef.current) return;
    const mesh = meshRef.current;

    // Set actual instance count (pre-allocated to MAX_INSTANCES)
    mesh.count = tasks.length;

    tasks.forEach((task, i) => {
      const width = task.duration * PX_PER_DAY;
      const x = task.startDay * PX_PER_DAY + width / 2;
      const y = -task.trainIndex * PX_PER_TRAIN - PX_PER_TRAIN / 2;

      // Z-ordering: selection > focus > conflict > hover > normal
      const isSelected = task.id === selectedTaskId;
      const isFocused = task.id === focusedTaskId;
      const isHovered = task.id === hoveredTaskId;

      const z = isSelected ? 0.2
              : isFocused ? 0.15
              : task.hasConflict ? 0.1
              : isHovered ? 0.05
              : 0;

      // Transform
      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, TASK_HEIGHT, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);

      // Color
      const baseColor = COLORS[task.color] ?? COLORS.gray;

      if (task.hasConflict) {
        tempColor.set(CONFLICT_COLOR);
      } else if (isSelected) {
        tempColor.set(SELECTION_COLOR);
      } else if (isFocused) {
        tempColor.set(FOCUS_COLOR);
      } else if (isHovered) {
        tempColor.set(baseColor);
        tempColor.offsetHSL(0, 0, HOVER_BRIGHTNESS);
      } else {
        tempColor.set(baseColor);
      }

      mesh.setColorAt(i, tempColor);
    });

    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId, focusedTaskId]);

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, MAX_INSTANCES]}  // Pre-allocate
    >
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial
        toneMapped={false}
        transparent={opacity < 1}
        opacity={opacity}
        depthWrite={opacity >= 0.5}
        vertexColors
      />
    </instancedMesh>
  );
}
```

