### 12.2 Crossfade Transitions

```typescript
const LOD_THRESHOLDS = {
  macroToMeso: 0.5,
  mesoToMicro: 2.0,
};
const BLEND_ZONE_SIZE = 0.15;

function calculateLayerOpacities(zoom: number): {
  macro: number; meso: number; micro: number;
} {
  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;

  const macroEnd = macroToMeso - BLEND_ZONE_SIZE;
  const mesoStart = macroToMeso + BLEND_ZONE_SIZE;
  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE;
  const microStart = mesoToMicro + BLEND_ZONE_SIZE;

  let macro = 0, meso = 0, micro = 0;

  if (zoom <= macroEnd) macro = 1;
  else if (zoom < mesoStart) {
    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    macro = 1 - t;
    meso = t;
  } else if (zoom <= mesoEnd) {
    meso = 1;
  } else if (zoom < microStart) {
    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    meso = 1 - t;
    micro = t;
  } else {
    micro = 1;
  }

  return { macro, meso, micro };
}
```

