#### MesoLayer

```typescript
const MAX_INSTANCES = 100000;
const TASK_HEIGHT = 18;

const COLORS = {
  blue: '#3b82f6',
  orange: '#f59e0b',
  gray: '#9ca3af',
};
const CONFLICT_COLOR = '#ef4444';

export function MesoLayer({ tasks, opacity = 1 }) {
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);
  const tempColor = useMemo(() => new Color(), []);

  useEffect(() => {
    if (!meshRef.current) return;
    meshRef.current.count = tasks.length;

    tasks.forEach((task, i) => {
      const width = task.duration * PX_PER_DAY;
      const x = task.startDay * PX_PER_DAY + width / 2;
      const y = -task.trainIndex * PX_PER_TRAIN - PX_PER_TRAIN / 2;

      tempObject.position.set(x, y, 0);
      tempObject.scale.set(width, TASK_HEIGHT, 1);
      tempObject.updateMatrix();
      meshRef.current.setMatrixAt(i, tempObject.matrix);

      const color = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
      tempColor.set(color);
      meshRef.current.setColorAt(i, tempColor);
    });

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) {
      meshRef.current.instanceColor.needsUpdate = true;
    }
  }, [tasks]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_INSTANCES]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial toneMapped={false} transparent={opacity < 1}
        opacity={opacity} depthWrite={opacity >= 0.5} vertexColors />
    </instancedMesh>
  );
}
```

