    isInitialized: false,
    momentum: { velocityX: 0, velocityY: 0, isActive: false },
    animation: {
      isAnimating: false, startTime: 0, duration: 250,
      startX: 0, startY: 0, startZoom: 1,
      targetX: 0, targetY: 0, targetZoom: 1,
    },
    isPanning: false,
    panStart: { x: 0, y: 0, zoom: 1 },
    cameraPosAtPanStart: { x: 0, y: 0, zoom: 1 },
  },
  cache: { policy: 'session' },
  reducers: {
    setCamera(state, payload: CameraPosition) { state.camera = payload; },
    setZoom(state, payload: number) { state.camera.zoom = payload; },
    setCanvasSize(state, payload: { width: number; height: number }) {
      state.canvasSize = payload;
      state.isInitialized = true;
    },
    startPan(state, payload: { x: number; y: number }) {
      state.isPanning = true;
      state.panStart = { x: payload.x, y: payload.y, zoom: state.camera.zoom };
      state.cameraPosAtPanStart = { ...state.camera };
    },
    endPan(state) { state.isPanning = false; },
    startMomentum(state, payload: { velocityX: number; velocityY: number }) {
      state.momentum = { ...payload, isActive: true };
    },
    stopMomentum(state) {
      state.momentum = { velocityX: 0, velocityY: 0, isActive: false };
    },
    reset() { return viewportSlice.initial; },
  },
});
